import{_ as e,o as s,c as a,V as o}from"./chunks/framework.819a0b42.js";const y=JSON.parse('{"title":"Getting started","description":"","frontmatter":{"title":"Getting started","date":"2023-03-23T14:27:31.000Z","layout":"post","tags":["intro"],"cover":{"image":"https://user-images.githubusercontent.com/65269574/227759806-0ac36549-9ada-426b-8c67-50c0ae04b3d9.png","position":"left"}},"headers":[],"relativePath":"content/posts/Hello.md"}'),t={name:"content/posts/Hello.md"},n=o(`<h2 id="_1-安装主题" tabindex="-1">1. 安装主题 <a class="header-anchor" href="#_1-安装主题" aria-label="Permalink to &quot;1. 安装主题&quot;">​</a></h2><p>在 <a href="https://github.com/fzdwx/vitepress-blog-theme/releases" target="_blank" rel="noreferrer">https://github.com/fzdwx/vitepress-blog-theme/releases</a> 页面下载操作系统对应的 bang 压缩文件.</p><blockquote><p>bang 是 vitepress-blog-theme 的命令行工具, 用于快速创建博客, 更新主题等</p></blockquote><p>然后运行 <code>bang init</code></p><p>就会在当前目录下生成一个 <code>vitepress-blog-theme</code> 的文件夹, 这个其实也是通过 <code>git clone</code> 实现的, 只是删除了一些不必要的文件</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 运行项目</span></span>
<span class="line"><span style="color:#82AAFF;">cd</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">vitepress-blog-theme</span></span>
<span class="line"><span style="color:#FFCB6B;">pnpm</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">i</span></span>
<span class="line"><span style="color:#FFCB6B;">pnpm</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">dev</span></span></code></pre></div><p>接下来可以运行 <code>bang new</code> 来创建一篇文章,</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">bang</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">new</span><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;"># 交互式创建文章</span></span>
<span class="line"><span style="color:#FFCB6B;">bang</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">new</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-t</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">文章标题</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;"># 直接创建文章</span></span>
<span class="line"><span style="color:#FFCB6B;">bang</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-t</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">标题</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-l</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">post</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-g</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">group</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">new</span><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;"># -l 支持 post, doc, -g 只在 doc 下使用</span></span></code></pre></div><p>所有的文章都在 <code>content/</code> 文件夹下</p><p>如果后续需要更新主题, 可以使用 <code>bang update</code> 命令</p><h2 id="_2-部署" tabindex="-1">2. 部署 <a class="header-anchor" href="#_2-部署" aria-label="Permalink to &quot;2. 部署&quot;">​</a></h2><p>可以通过 <code>Github action</code> 自动部署到 <code>Github Pages</code> 上, 也可以使用 <code>Vercel</code>.</p><h3 id="_2-1-github-action" tabindex="-1">2.1 Github action <a class="header-anchor" href="#_2-1-github-action" aria-label="Permalink to &quot;2.1 Github action&quot;">​</a></h3><p>如果使用 <code>Github action</code> 部署, 仅需将 <code>deploy.yml.example</code> 重命名为 <code>deploy.yml</code> 即可</p><p><img src="https://user-images.githubusercontent.com/65269574/227693247-cd247b3c-bf2d-4ceb-8f8a-9df58c8a4150.png" alt="image"></p><h3 id="_2-2-vercel" tabindex="-1">2.2 Vercel <a class="header-anchor" href="#_2-2-vercel" aria-label="Permalink to &quot;2.2 Vercel&quot;">​</a></h3><p>需要修改构建命令为:</p><p><img src="https://user-images.githubusercontent.com/65269574/227693554-f851cf22-dd51-48db-9fd5-d81446227862.png" alt="image"></p><p>更多配置请参考 <a href="https://vitepress.dev/guide/deploy#netlify-vercel-cloudflare-pages-aws-amplify-render" target="_blank" rel="noreferrer">https://vitepress.dev/guide/deploy#netlify-vercel-cloudflare-pages-aws-amplify-render</a></p><h2 id="_3-note" tabindex="-1">3. Note <a class="header-anchor" href="#_3-note" aria-label="Permalink to &quot;3. Note&quot;">​</a></h2><ol><li>设置 Github token 到 <code>Github action</code> 中 <img src="https://user-images.githubusercontent.com/65269574/227569403-ac21c7fa-ed22-45e2-824d-1fa293ce0ac7.png" alt="image"></li><li>修改 <code>repo</code> 为你当前仓库的名称 <img src="https://user-images.githubusercontent.com/65269574/227692648-79b74a2e-b597-40a3-a7c0-6acc85a75d5a.png" alt="image"></li><li>Github action 需要开启读写权限 <code>Read and write permissions</code><img src="https://user-images.githubusercontent.com/65269574/227569746-8e615cca-69f4-488c-a1a9-5849eb40327f.png" alt="image"></li></ol>`,21),l=[n];function p(c,r,i,d,h,g){return s(),a("div",null,l)}const C=e(t,[["render",p]]);export{y as __pageData,C as default};
